	LastActivityAnnotationKey = "agentcube.volcano.sh/last-activity"
)

type Reconciler struct {
	client.Client
	Scheme *runtime.Scheme
}

func (r *Reconciler) Reconcile(ctx context.Context, req reconcile.Request) (reconcile.Result, error) {
	log := log.FromContext(ctx)

	sandbox := &sandboxv1alpha1.Sandbox{}
	if err := r.Get(ctx, req.NamespacedName, sandbox); err != nil {
		if errors.IsNotFound(err) {
			return reconcile.Result{}, nil
		}
		return reconcile.Result{}, err
	}

	lastActivityStr, ok := sandbox.Annotations[LastActivityAnnotationKey]
	if !ok || lastActivityStr == "" {
		return reconcile.Result{}, nil
	}

	lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
	if err != nil {
		log.Error(err, "Failed to parse last activity time", "annotation", lastActivityStr)
		return reconcile.Result{RequeueAfter: 30 * time.Second}, err
	}

	expiration := lastActivity.Add(SessionExpirationTimeout)
	if time.Now().After(expiration) {
		log.Info("Deleting sandbox due to inactivity", "sandbox", req.NamespacedName)
		if err := r.Delete(ctx, sandbox); err != nil {
			return reconcile.Result{}, err
		}
		return reconcile.Result{}, nil
	}

	return reconcile.Result{RequeueAfter: time.Until(expiration)}, nil
}

func (r *Reconciler) SetupWithManager(mgr manager.Manager) error {
