package main

import (
	"flag"
	"os"

	"github.com/volcano-sh/agentcube/pkg/router"
	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/klog/v2"
)

func main() {
	port := flag.Int("port", 8080, "Port to listen on")
	enableTLS := flag.Bool("enable-tls", false, "Enable TLS")
	tlsCert := flag.String("tls-cert", "", "TLS certificate file")
	tlsKey := flag.String("tls-key", "", "TLS key file")
	debug := flag.Bool("debug", false, "Enable debug mode")
	maxConcurrentRequests := flag.Int("max-concurrent-requests", 1000, "Maximum concurrent requests")
	flag.Parse()

	klog.InitFlags(nil)

	config := &router.Config{
		Port:                  *port,
		EnableTLS:             *enableTLS,
		TLSCert:               *tlsCert,
		TLSKey:                *tlsKey,
		Debug:                 *debug,
		MaxConcurrentRequests: *maxConcurrentRequests,
	}

	server, err := router.NewServer(config, store.Storage())
	if err != nil {
		klog.Fatalf("Failed to create server: %v", err)
	}

	if err := server.Start(); err != nil {
		klog.Fatalf("Server error: %v", err)
	}
}

