package router

import (
	"context"
	"crypto/tls"
	"fmt"
	"net"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/gin-gonic/gin"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"
	"k8s.io/klog/v2"
)

type Server struct {
	config         *Config
	engine         *gin.Engine
	httpServer     *http.Server
	sessionManager *SessionManager
	storeClient    StoreClient
	httpTransport  *http.Transport
	jwtManager     *JWTManager
}

func NewServer(config *Config) (*Server, error) {
	if config.MaxConcurrentRequests == 0 {
		config.MaxConcurrentRequests = 1000
	}

	if config.Port == 0 {
		config.Port = 8080
	}

	gin.SetMode(gin.ReleaseMode)
	if config.Debug {
		gin.SetMode(gin.DebugMode)
	}

	engine := gin.New()
	engine.Use(gin.Logger())
	engine.Use(gin.Recovery())

	storeClient := NewStoreClient()
	jwtManager, err := NewJWTManager()
	if err != nil {
		return nil, fmt.Errorf("failed to create JWT manager: %w", err)
	}

	sessionManager := NewSessionManager(storeClient)

	srv := &Server{
		config:         config,
		engine:         engine,
		storeClient:    storeClient,
		jwtManager:     jwtManager,
		sessionManager: sessionManager,
	}

	srv.registerRoutes()

	return srv, nil
}

func (s *Server) Start() error {
	addr := fmt.Sprintf(":%d", s.config.Port)

	s.httpServer = &http.Server{
		Addr:         addr,
		Handler:      s.createHandler(),
		ReadTimeout:  30 * time.Second,
		IdleTimeout:  90 * time.Second,
		WriteTimeout: 30 * time.Second,
	}

	if s.config.EnableTLS {
		cert, err := tls.LoadX509KeyPair(s.config.TLSCert, s.config.TLSKey)
		if err != nil {
			return fmt.Errorf("failed to load TLS certificates: %w", err)
		}
		s.httpServer.TLSConfig = &tls.Config{
			Certificates: []tls.Certificate{cert},
			NextProtos:   []string{"h2", "http/1.1"},
		}
	}

	go func() {
		klog.Infof("Starting router server on %s", addr)
		if s.config.EnableTLS {
			if err := s.httpServer.ListenAndServeTLS("", ""); err != nil && err != http.ErrServerClosed {
				klog.Fatalf("Server error: %v", err)
			}
		} else {
			if err := s.httpServer.ListenAndServe(); err != nil && err != http.ErrServerClosed {
				klog.Fatalf("Server error: %v", err)
			}
		}
	}()

	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)
	<-quit

	klog.Info("Shutting down server...")
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	if err := s.httpServer.Shutdown(ctx); err != nil {
		klog.Errorf("Server shutdown error: %v", err)
		return err
	}

	klog.Info("Server stopped")
	return nil
}

func (s *Server) createHandler() http.Handler {
	if s.config.EnableTLS {
		return s.engine
	}
	return h2c.NewHandler(s.engine, &http2.Server{})
}

func (s *Server) registerRoutes() {
	s.engine.GET("/health/live", s.handleHealthLive)
	s.engine.GET("/health/ready", s.handleHealthReady)

	v1Group := s.engine.Group("/v1")
	v1Group.Use(concurrencyLimitMiddleware(s.config.MaxConcurrentRequests))

	agentGroup := v1Group.Group("/namespaces/:namespace/agent-runtimes/:name")
	agentGroup.Any("/invocations/*path", s.handleAgentInvoke)

	codeGroup := v1Group.Group("/namespaces/:namespace/code-interpreters/:name")
	codeGroup.Any("/invocations/*path", s.handleCodeInterpreterInvoke)
}

func (s *Server) handleHealthLive(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

func (s *Server) handleHealthReady(c *gin.Context) {
	if err := s.storeClient.Ping(); err != nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{
			"status": "not ready",
			"error":  err.Error(),
		})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

