	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	if err := s.httpServer.Shutdown(ctx); err != nil {
		klog.Errorf("Server shutdown error: %v", err)
		return err
	}

	klog.Info("Server stopped")
	return nil
}

func (s *Server) createHandler() http.Handler {
	if s.config.EnableTLS {
		return s.engine
	}
	return h2c.NewHandler(s.engine, &http2.Server{})
}

func (s *Server) registerRoutes() {
	s.engine.GET("/health/live", s.handleHealthLive)
	s.engine.GET("/health/ready", s.handleHealthReady)

	v1Group := s.engine.Group("/v1")
	v1Group.Use(concurrencyLimitMiddleware(s.config.MaxConcurrentRequests))

	agentGroup := v1Group.Group("/namespaces/:namespace/agent-runtimes/:name")
	agentGroup.Any("/invocations/*path", s.handleAgentInvoke)

	codeGroup := v1Group.Group("/namespaces/:namespace/code-interpreters/:name")
	codeGroup.Any("/invocations/*path", s.handleCodeInterpreterInvoke)
}

func (s *Server) handleHealthLive(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

func (s *Server) handleHealthReady(c *gin.Context) {
	if err := s.storeClient.Ping(); err != nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{
			"status": "not ready",
			"error":  err.Error(),
		})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

