package workloadmanager

import (
	"context"
	"fmt"
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/klog/v2"
)

type Config struct {
	Port             int
	RuntimeClassName string
	EnableTLS        bool
	TLSCert          string
	TLSKey           string
	EnableAuth       bool
}

type Server struct {
	config       *Config
	router       *gin.Engine
	httpServer   *http.Server
	k8sClient    *K8sClient
	sandboxCtrl  *SandboxController
	storeClient  store.Store
}

func NewServer(config *Config) (*Server, error) {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()
	router.Use(gin.Logger())
	router.Use(gin.Recovery())

	storeClient := store.Storage()
	k8sClient := NewK8sClient()

	sandboxCtrl := NewSandboxController(k8sClient, storeClient)

	srv := &Server{
		config:      config,
		router:      router,
		k8sClient:   k8sClient,
		sandboxCtrl: sandboxCtrl,
		storeClient: storeClient,
	}

	srv.registerRoutes()

	return srv, nil
}

func (s *Server) Start(ctx context.Context) error {
	addr := fmt.Sprintf(":%d", s.config.Port)

	s.httpServer = &http.Server{
		Addr:    addr,
		Handler: s.router,
	}

	go func() {
		klog.Infof("Starting workload manager server on %s", addr)
		if s.config.EnableTLS {
			if err := s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey); err != nil && err != http.ErrServerClosed {
				klog.Fatalf("Server error: %v", err)
			}
		} else {
			if err := s.httpServer.ListenAndServe(); err != nil && err != http.ErrServerClosed {
				klog.Fatalf("Server error: %v", err)
			}
		}
	}()

	<-ctx.Done()

	klog.Info("Shutting down server...")
	shutdownCtx, cancel := context.WithTimeout(context.Background(), 15*time.Second)
	defer cancel()

	if err := s.httpServer.Shutdown(shutdownCtx); err != nil {
		klog.Errorf("Server shutdown error: %v", err)
		return err
	}

	klog.Info("Server stopped")
	return nil
}

func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}

func (s *Server) registerRoutes() {
	s.router.GET("/health", s.handleHealth)

	v1Group := s.router.Group("/v1")
	v1Group.POST("/agent-runtime", s.handleAgentRuntimeCreate)
	v1Group.DELETE("/agent-runtime/sessions/:sessionId", s.handleDeleteSandbox)
	v1Group.POST("/code-interpreter", s.handleCodeInterpreterCreate)
	v1Group.DELETE("/code-interpreter/sessions/:sessionId", s.handleDeleteSandbox)
}

func (s *Server) handleAgentRuntimeCreate(c *gin.Context) {
	var req store.CreateSandboxRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	req.Kind = "AgentRuntime"

	resp, err := s.sandboxCtrl.CreateSandbox(c.Request.Context(), &req)
	if err != nil {
		klog.Errorf("Failed to create agent runtime: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, resp)
}

func (s *Server) handleCodeInterpreterCreate(c *gin.Context) {
	var req store.CreateSandboxRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	req.Kind = "CodeInterpreter"

	resp, err := s.sandboxCtrl.CreateSandbox(c.Request.Context(), &req)
	if err != nil {
		klog.Errorf("Failed to create code interpreter: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, resp)
}

func (s *Server) handleDeleteSandbox(c *gin.Context) {
	sessionID := c.Param("sessionId")

	err := s.sandboxCtrl.DeleteSandbox(c.Request.Context(), sessionID)
	if err != nil {
		klog.Errorf("Failed to delete sandbox: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "Sandbox deleted successfully"})
}

