package workloadmanager

import (
	"context"
	"time"

	"github.com/volcano-sh/agentcube/pkg/store"
)

type GarbageCollector struct {
	k8sClient  *K8sClient
	store      store.Store
	interval   time.Duration
}

func NewGarbageCollector(k8sClient *K8sClient, storeClient store.Store) *GarbageCollector {
	return &GarbageCollector{
		k8sClient: k8sClient,
		store:     storeClient,
		interval:  15 * time.Second,
	}
}

func (gc *GarbageCollector) Start(ctx context.Context) {
	ticker := time.NewTicker(gc.interval)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			gc.cleanup(ctx)
		case <-ctx.Done():
			return
		}
	}
}

func (gc *GarbageCollector) cleanup(ctx context.Context) {
	inactiveTimeout := 15 * time.Minute
	now := time.Now()

	inactive, err := gc.store.ListInactiveSandboxes(ctx, now.Add(-inactiveTimeout), 16)
	if err != nil {
		return
	}

	expired, err := gc.store.ListExpiredSandboxes(ctx, now, 16)
	if err != nil {
		return
	}

	sandboxes := append(inactive, expired...)
	for _, sandbox := range sandboxes {
		_ = gc.store.DeleteSandboxBySessionID(ctx, sandbox.SessionID)
	}
}

