	if err != nil {
		kubeconfig := clientcmd.NewDefaultClientConfigLoadingRules().GetDefaultFilename()
		config, err = clientcmd.BuildConfigFromFlags("", kubeconfig)
		if err != nil {
			panic(err.Error())
		}
	}

	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		panic(err.Error())
	}

	return &K8sClient{
		clientset:  clientset,
		baseConfig: config,
		AgentRuntimeGVR: metav1.GroupVersionResource{
			Group:    "runtime.agentcube.volcano.sh",
			Version:  "v1alpha1",
			Resource: "agentruntimes",
		},
		CodeInterpreterGVR: metav1.GroupVersionResource{
			Group:    "runtime.agentcube.volcano.sh",
			Version:  "v1alpha1",
			Resource: "codeinterpreters",
		},
		SandboxGVR: metav1.GroupVersionResource{
			Group:    "agents.x-k8s.io",
			Version:  "v1alpha1",
			Resource: "sandboxes",
		},
	}
}

