	return k.clientset.CoreV1().Pods(namespace).List(ctx, opts)
}

func (k *K8sClient) GetClientset() kubernetes.Interface {
	return k.clientset
}

func (k *K8sClient) GetConfig() *rest.Config {
	return k.baseConfig
}

