		panic(err.Error())
	}
	return &K8sClient{clientset: clientset}
}

func NewSandboxController(k8sClient *K8sClient, storeClient store.Store) *SandboxController {
	return &SandboxController{
		k8sClient: k8sClient,
		store:     storeClient,
	}
}

func (c *SandboxController) CreateSandbox(ctx context.Context, req *types.CreateSandboxRequest) (*types.CreateSandboxResponse, error) {
	if err := req.Validate(); err != nil {
		return nil, err
	}

	sessionID := generateSessionID()

	sandbox := &types.SandboxInfo{
		SessionID:        sessionID,
		SandboxID:        generateSandboxID(),
		SandboxNamespace: req.Namespace,
		Name:             req.Name,
		Kind:             req.Kind,
		CreatedAt:        time.Now(),
		ExpiresAt:        timePtr(time.Now().Add(8 * time.Hour)),
		Status:           "running",
		EntryPoints: []types.SandboxEntryPoint{
			{
				Path:     "/",
				Protocol: "HTTP",
				Endpoint: fmt.Sprintf("%s.%s.svc.cluster.local:8080", req.Name, req.Namespace),
			},
		},
	}

	if err := c.store.StoreSandbox(ctx, sessionID, sandbox); err != nil {
		return nil, err
	}

	return &types.CreateSandboxResponse{
		SessionID:   sessionID,
		SandboxID:   sandbox.SandboxID,
		SandboxName: req.Name,
		EntryPoints: sandbox.EntryPoints,
	}, nil
}

func (c *SandboxController) DeleteSandbox(ctx context.Context, sessionID string) error {
	if err := c.store.DeleteSandboxBySessionID(ctx, sessionID); err != nil {
		return err
	}
	return nil
}

func generateSessionID() string {
	b := make([]byte, 16)
	rand.Read(b)
	return hex.EncodeToString(b)
}

func generateSandboxID() string {
	b := make([]byte, 16)
	rand.Read(b)
	return hex.EncodeToString(b)
}

func timePtr(t time.Time) *time.Time {
	return &t
}
